// Extract YST pair data from DexScreener response
const data = $input.first().json;

// DexScreener returns array of pairs; find SOL pair first, else use first pair
const pairs = data.pairs || [];
const ystPair = pairs.find(p =>
  p.quoteToken && p.quoteToken.symbol === 'SOL'
) || pairs[0] || {};

const priceUsd = parseFloat(ystPair.priceUsd || 0);
const priceNative = parseFloat(ystPair.priceNative || 0);
const volume24h = ystPair.volume?.h24 || 0;
const priceChange24h = ystPair.priceChange?.h24 || 0;
const liquidity = ystPair.liquidity?.usd || 0;
const fdv = ystPair.fdv || 0;
const marketCap = ystPair.marketCap || 0;
const buys24h = ystPair.txns?.h24?.buys || 0;
const sells24h = ystPair.txns?.h24?.sells || 0;
const pairAddress = ystPair.pairAddress || '';
const pairUrl = ystPair.url || (pairAddress ? `https://dexscreener.com/solana/${pairAddress}` : 'https://dexscreener.com/solana/jYwmSavfx69a35JEkpyrxu9JUjvswEvfnhLCDV9vREV');

return [{
  json: {
    dexscreener: {
      priceUsd,
      priceNative,
      volume24h,
      priceChange24h,
      liquidity,
      fdv,
      marketCap,
      buys24h,
      sells24h,
      pairAddress,
      pairUrl
    }
  }
}];

// Extract total supply from Solana RPC getTokenSupply response
const rpcData = $input.first().json;
const supplyInfo = rpcData?.result?.value || {};

const rawAmount = supplyInfo.amount || '0';
const decimals = supplyInfo.decimals || 6;
const uiAmount = supplyInfo.uiAmount || parseFloat(rawAmount) / Math.pow(10, decimals);
const uiAmountString = supplyInfo.uiAmountString || String(uiAmount);

return [{
  json: {
    supply: {
      raw: rawAmount,
      decimals,
      total: uiAmount,
      totalFormatted: uiAmountString
    }
  }
}];

// Combine DexScreener + Solana RPC supply data into final payload
const items = $input.all();

const dexItem = items.find(i => i.json.dexscreener) || items[0];
const supplyItem = items.find(i => i.json.supply) || items[1];

const dex = dexItem?.json?.dexscreener || {};
const supply = supplyItem?.json?.supply || {};

const timestamp = new Date().toISOString();

const output = {
  token: 'YST',
  name: 'Yakk Studios Token',
  mint: 'jYwmSavfx69a35JEkpyrxu9JUjvswEvfnhLCDV9vREV',
  chain: 'solana',
  timestamp,
  price: {
    usd: dex.priceUsd || 0,
    sol: dex.priceNative || 0
  },
  change24h: dex.priceChange24h || 0,
  volume: {
    h24: dex.volume24h || 0
  },
  liquidity: {
    usd: dex.liquidity || 0
  },
  marketCap: dex.marketCap || 0,
  fdv: dex.fdv || 0,
  transactions: {
    buys24h: dex.buys24h || 0,
    sells24h: dex.sells24h || 0,
    total24h: (dex.buys24h || 0) + (dex.sells24h || 0)
  },
  supply: {
    total: supply.total || 0,
    totalFormatted: supply.totalFormatted || '0',
    decimals: supply.decimals || 6
  },
  links: {
    dexscreener: dex.pairUrl || 'https://dexscreener.com/solana/jYwmSavfx69a35JEkpyrxu9JUjvswEvfnhLCDV9vREV',
    solscan: 'https://solscan.io/token/jYwmSavfx69a35JEkpyrxu9JUjvswEvfnhLCDV9vREV'
  }
};

// Cache result in static data so the webhook can serve it instantly
const staticData = $getWorkflowStaticData('global');
staticData.lastPriceData = output;
staticData.lastUpdated = timestamp;

return [{ json: output }];

// Webhook path: serve cached price data from static data
const staticData = $getWorkflowStaticData('global');

if (staticData.lastPriceData) {
  return [{ json: staticData.lastPriceData }];
}

// If no cache yet, return a placeholder
return [{ json: {
  token: 'YST',
  name: 'Yakk Studios Token',
  mint: 'jYwmSavfx69a35JEkpyrxu9JUjvswEvfnhLCDV9vREV',
  chain: 'solana',
  timestamp: new Date().toISOString(),
  message: 'Data not yet available. Schedule trigger runs every 15min.',
  price: { usd: 0, sol: 0 }
} }];
